CREATE TABLE IF NOT EXISTS calls (id UUID PRIMARY KEY, started_at TIMESTAMPTZ NOT NULL DEFAULT now(), ended_at TIMESTAMPTZ, metadata JSONB NOT NULL DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS segments (id UUID PRIMARY KEY, call_id UUID REFERENCES calls(id), speaker_id INT NOT NULL, original_transcript TEXT NOT NULL, interpretation TEXT NOT NULL, detected_language TEXT NOT NULL, target_language TEXT NOT NULL, confidence INT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS qa_events (id UUID PRIMARY KEY, segment_id UUID REFERENCES segments(id), action TEXT NOT NULL, actor TEXT NOT NULL, payload JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS corrections (id UUID PRIMARY KEY, segment_id UUID REFERENCES segments(id), original_transcript TEXT NOT NULL, ai_interpretation TEXT NOT NULL, human_correction TEXT NOT NULL, confidence_score INT NOT NULL, speaker_id INT NOT NULL, medical_specialty TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS medical_glossary (id UUID PRIMARY KEY, source_term TEXT NOT NULL, target_term TEXT NOT NULL, note TEXT, specialty TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS style_profile (id UUID PRIMARY KEY, profile JSONB NOT NULL, active BOOLEAN NOT NULL DEFAULT true, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS learning_dataset (id UUID PRIMARY KEY, correction_id UUID REFERENCES corrections(id), row JSONB NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS latency_logs (id UUID PRIMARY KEY, call_id UUID REFERENCES calls(id), component TEXT NOT NULL, latency_ms NUMERIC NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
